import React from 'react';
import { graphql } from 'gatsby';
import { makeStyles } from '@material-ui/core/styles';
import PhotosPage from '../../templates/PhotosPage';

const useStyles = makeStyles((theme) => ({
    // TODO
}));

const E3_2019 = (props) => {
    const { data } = props;
    const classes = useStyles();

    return (
        <PhotosPage
            images={data?.images}
            title="e3_2019_photos.title"
            description="e3_2019_photos.description"
        />
    );
};

export default E3_2019;

export const pageQuery = graphql`
    query {
        images: allImage(
            filter: { googlePhotosAlbumId: { eq: "nZCG28mvHQixQHUS6" }}
        ) {
            edges {
                node {
                    url
                    googlePhotosAlbumId
                    image {
                        publicURL
                        childImageSharp {
                            original{
                                width
                                height
                                src
                            }
                            small: fluid(maxWidth: 600) {
                                ...GatsbyImageSharpFluid_tracedSVG
                                originalImg
                            }
                            large: fluid(maxWidth: 1800) {
                                ...GatsbyImageSharpFluid_tracedSVG
                                originalImg
                            }
                        }
                    }
                }
            }
        }
    }
`;
